+    [[fallthrough]];
+  }
+  case Intrinsic::umax: {
+    if (IID == Intrinsic::umax) {
+      Value *LHS = II->getArgOperand(0);
+      Value *RHS = II->getArgOperand(1);
+      Value *X;
+      
+      // Pattern: umax(2*x, x+1) -> x == 0 ? 1 : 2*x
+      // This works when both operations are nuw (no unsigned wrap)
+      // Try to match umax(2*x, x+1)
+      if (match(LHS, m_NUWShl(m_Value(X), m_SpecificInt(1))) &&
+          match(RHS, m_NUWAdd(m_Deferred(X), m_SpecificInt(1)))) {
+        // Create comparison: x == 0
+        Value *IsZero = Builder.CreateICmpEQ(X, ConstantInt::get(X->getType(), 0));
+        // Create select: x == 0 ? 1 : 2*x
+        Value *Select = Builder.CreateSelect(IsZero, 
+                                             ConstantInt::get(X->getType(), 1),
+                                             LHS);
+        return replaceInstUsesWith(CI, Select);
+      }
+      
+      // Also try the symmetric case: umax(x+1, 2*x)
+      if (match(RHS, m_NUWShl(m_Value(X), m_SpecificInt(1))) &&
+          match(LHS, m_NUWAdd(m_Deferred(X), m_SpecificInt(1)))) {
+        // Create comparison: x == 0
+        Value *IsZero = Builder.CreateICmpEQ(X, ConstantInt::get(X->getType(), 0));
+        // Create select: x == 0 ? 1 : 2*x
+        Value *Select = Builder.CreateSelect(IsZero,
+                                             ConstantInt::get(X->getType(), 1),
+                                             RHS);
+        return replaceInstUsesWith(CI, Select);
+      }
+    }
     [[fallthrough]];
   }
   case Intrinsic::vector_reduce_xor: {
